import React, { useState, useRef, useMemo, useEffect } from 'react';
import { Stage, Layer, Circle, Text, Group } from 'react-konva';
import html2canvas from 'html2canvas';

const SIZE = 600;
const CENTER = SIZE / 2;
const STEP = SIZE / 22; 
const MM_PER_PIXEL = 8 / STEP; 

function App() {
  const [shots, setShots] = useState([]);
  const [stageScale, setStageScale] = useState(1);
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [mmPerClick, setMmPerClick] = useState(1.0); 
  const [showCorrection, setShowCorrection] = useState(false);
  
  const [currentView, setCurrentView] = useState('shooting'); 
  const [savedSessions, setSavedSessions] = useState([]);
  const [sortBy, setSortBy] = useState('date'); // 'date' أو 'score'

  useEffect(() => {
    const data = localStorage.getItem('shooting_history_v2');
    if (data) setSavedSessions(JSON.parse(data));
  }, []);

  // دالة الفرز والترتيب
  const sortedSessions = useMemo(() => {
    let sorted = [...savedSessions];
    if (sortBy === 'score') {
      return sorted.sort((a, b) => b.total - a.total); // من الأعلى نتيجة للأقل
    } else {
      return sorted.sort((a, b) => b.id - a.id); // من الأحدث للأقدم
    }
  }, [savedSessions, sortBy]);

  const saveSession = () => {
    if (shots.length === 0) return alert("لا توجد طلقات لحفظها");
    const newSession = {
      id: Date.now(),
      date: new Date().toLocaleString(),
      shots: shots,
      mmPerClick: mmPerClick,
      total: grandTotal
    };
    const updated = [newSession, ...savedSessions];
    setSavedSessions(updated);
    localStorage.setItem('shooting_history_v2', JSON.stringify(updated));
    alert("✅ تم حفظ الجلسة بنجاح");
  };

  const loadSession = (session) => {
    setShots(session.shots);
    setMmPerClick(session.mmPerClick);
    setCurrentView('shooting');
  };

  const dragStartPos = useRef({ x: 0, y: 0 });
  const reportRef = useRef(null);
  const roundColors = ['#FF0000', '#0000FF', '#7CFC00', '#800080', '#FF8C00', '#00CED1'];

  const getScoreFromDist = (dist) => {
    const bulletRadius = 6;
    const effectiveDist = Math.max(0, dist - bulletRadius);
    const ring = Math.floor(effectiveDist / STEP);
    return Math.max(0, 10 - ring);
  };

  const analysis = useMemo(() => {
    if (shots.length === 0) return { driftX: 0, driftY: 0, driftX_px: 0, driftY_px: 0, suggestion: "ابدأ بالرمي للتحليل" };
    const avgX = shots.reduce((sum, s) => sum + s.x, 0) / shots.length;
    const avgY = shots.reduce((sum, s) => sum + s.y, 0) / shots.length;
    const driftX_mm = (avgX - CENTER) * MM_PER_PIXEL;
    const driftY_mm = (avgY - CENTER) * MM_PER_PIXEL;
    const driftX_px = (avgX - CENTER);
    const driftY_px = (avgY - CENTER);
    const clicksX = Math.round(Math.abs(driftX_mm) / (mmPerClick || 1));
    const clicksY = Math.round(Math.abs(driftY_mm) / (mmPerClick || 1));
    
    let suggestion = "النيشان مضبوط";
    if (Math.abs(driftX_mm) > 2 || Math.abs(driftY_mm) > 2) {
      const h = driftX_mm > 2 ? `يمين (عدل يسار ${clicksX} تكة)` : driftX_mm < -2 ? `يسار (عدل يمين ${clicksX} تكة)` : "";
      const v = driftY_mm > 2 ? `أسفل (عدل أعلى ${clicksY} تكة)` : driftY_mm < -2 ? `أعلى (عدل أسفل ${clicksY} تكة)` : "";
      suggestion = `ضبط: ${h} ${v}`.trim();
    }
    return { driftX: driftX_mm.toFixed(1), driftY: driftY_mm.toFixed(1), driftX_px, driftY_px, suggestion };
  }, [shots, mmPerClick]);

  const correctedShots = useMemo(() => {
    return shots.map(s => ({ x: s.x - analysis.driftX_px, y: s.y - analysis.driftY_px }));
  }, [shots, analysis]);

  const projectedTotal = useMemo(() => {
    return correctedShots.reduce((sum, s) => {
      const dist = Math.sqrt((s.x - CENTER) ** 2 + (s.y - CENTER) ** 2);
      return sum + getScoreFromDist(dist);
    }, 0);
  }, [correctedShots]);

  const rounds = [];
  let grandTotal = 0;
  for (let i = 0; i < 6; i++) {
    const roundShots = shots.slice(i * 10, i * 10 + 10);
    const roundTotal = roundShots.reduce((a, b) => a + b.score, 0);
    rounds.push({ id: i + 1, shots: roundShots, total: roundTotal });
    grandTotal += roundTotal;
  }

  const exportReport = () => {
    if (reportRef.current) {
      const prevScale = stageScale; const prevPos = stagePos;
      setStageScale(1); setStagePos({ x: 0, y: 0 });
      setTimeout(async () => {
        const canvas = await html2canvas(reportRef.current, { scale: 1.5, backgroundColor: '#ffffff' });
        const link = document.createElement('a');
        link.download = `تقرير_الرماية_${grandTotal}.jpg`;
        link.href = canvas.toDataURL('image/jpeg', 0.8);
        link.click();
        setStageScale(prevScale); setStagePos(prevPos);
      }, 100);
    }
  };

  const addShot = (pointerPos, stage) => {
    if (shots.length >= 60) { alert("⚠️ اكتملت الجلسة"); return; }
    const pos = { x: (pointerPos.x - stage.x()) / stage.scaleX(), y: (pointerPos.y - stage.y()) / stage.scaleY() };
    const dist = Math.sqrt((pos.x - CENTER) ** 2 + (pos.y - CENTER) ** 2);
    setShots([...shots, { x: pos.x, y: pos.y, score: getScoreFromDist(dist) }]);
  };

  const handleMouseDown = (e) => { setIsDragging(true); dragStartPos.current = { x: e.evt.clientX, y: e.evt.clientY }; };
  const handleMouseMove = (e) => { if (!isDragging) return; const stage = e.target.getStage(); setStagePos({ x: stage.x() + e.evt.movementX, y: stage.y() + e.evt.movementY }); };
  const handleMouseUp = (e) => { setIsDragging(false); const dx = e.evt.clientX - dragStartPos.current.x; const dy = e.evt.clientY - dragStartPos.current.y; if (Math.sqrt(dx*dx + dy*dy) < 10) addShot(e.target.getStage().getPointerPosition(), e.target.getStage()); };
  const handleWheel = (e) => { e.evt.preventDefault(); const scaleBy = 1.1; const stage = e.target.getStage(); const oldScale = stage.scaleX(); const pointer = stage.getPointerPosition(); const mousePointTo = { x: (pointer.x - stage.x()) / oldScale, y: (pointer.y - stage.y()) / oldScale }; let newScale = e.evt.deltaY > 0 ? oldScale / scaleBy : oldScale * scaleBy; if (newScale < 1) newScale = 1; if (newScale > 5) newScale = 5; setStageScale(newScale); setStagePos({ x: pointer.x - mousePointTo.x * newScale, y: pointer.y - mousePointTo.y * newScale }); };
  const undo = () => setShots(shots.slice(0, -1));
  const reset = () => { setShots([]); setStageScale(1); setStagePos({ x: 0, y: 0 }); };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      
      {/* تبويبات التنقل */}
      <div style={{ display: 'flex', gap: '5px', marginBottom: '15px' }}>
        <button onClick={() => setCurrentView('shooting')} style={{...tabBtn, backgroundColor: currentView === 'shooting' ? '#2c3e50' : '#bdc3c7'}}>🎯 لوحة الرماية</button>
        <button onClick={() => setCurrentView('history')} style={{...tabBtn, backgroundColor: currentView === 'history' ? '#2c3e50' : '#bdc3c7'}}>📜 السجلات ({savedSessions.length})</button>
      </div>

      {currentView === 'shooting' ? (
        <>
          <div style={{ backgroundColor: '#f1f1f1', padding: '15px', borderRadius: '8px', marginBottom: '15px', display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap' }}>
            <label style={{ fontWeight: 'bold' }}>تكة (ملم): </label>
            <input type="number" step="0.1" value={mmPerClick} onChange={(e) => setMmPerClick(parseFloat(e.target.value))} style={{ padding: '5px', width: '60px' }} />
            <button onClick={() => setShowCorrection(!showCorrection)} style={{...btnStyle, backgroundColor: showCorrection ? '#e67e22' : '#95a5a6'}}>{showCorrection ? 'إخفاء التصحيح' : 'عرض التصحيح'}</button>
            <button onClick={saveSession} style={{...btnStyle, backgroundColor: '#2980b9'}}>💾 حفظ الجلسة</button>
            <div style={{ display: 'flex', gap: '10px', marginLeft: 'auto' }}>
                <button onClick={undo} style={btnStyle}>⬅️ تراجع</button>
                <button onClick={reset} style={{...btnStyle, backgroundColor: '#e74c3c'}}>🗑️ مسح</button>
                <button onClick={exportReport} style={{...btnStyle, backgroundColor: '#27ae60'}}>📸 تصدير</button>
            </div>
          </div>

          <div ref={reportRef} style={{ padding: '20px', backgroundColor: 'white', border: '1px solid #eee' }}>
            <h1 style={{ textAlign: 'center', color: '#2c3e50' }}>تقرير الرماية الاحترافي</h1>
            <div style={{ backgroundColor: '#2c3e50', color: 'white', padding: '15px', borderRadius: '8px', marginBottom: '15px' }}>
               <h3 style={{ margin: '0 0 5px 0' }}>🎯 التوصية:</h3>
               <p style={{ fontSize: '18px', fontWeight: 'bold', color: '#f1c40f' }}>{analysis.suggestion}</p>
            </div>

            <div style={{ textAlign: 'center', marginBottom: '20px', padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '8px' }}>
              <h2 style={{ margin: '5px 0' }}>🏆 المجموع الفعلي: {grandTotal}</h2>
              {showCorrection && <h2 style={{ margin: '5px 0', color: '#27ae60' }}>📈 المتوقع بعد التصحيح: {projectedTotal}</h2>}
            </div>

            <div style={{ display: 'flex', justifyContent: 'center' }}>
              <Stage width={SIZE} height={SIZE} onWheel={handleWheel} onMouseDown={handleMouseDown} onMouseUp={handleMouseUp} onMouseMove={handleMouseMove} scaleX={stageScale} scaleY={stageScale} x={stagePos.x} y={stagePos.y} style={{ border: '2px solid #2c3e50', cursor: isDragging ? 'grabbing' : 'crosshair' }}>
                 <Layer>
                   {[...Array(10)].map((_, i) => { 
                     const ring = i + 1; const radius = (11 - ring) * STEP; const isBlack = ring >= 7; 
                     return (<Group key={ring}><Circle x={CENTER} y={CENTER} radius={radius} fill={isBlack ? "#2c3e50" : "white"} stroke={isBlack ? "white" : "#2c3e50"} strokeWidth={2} />{ring <= 8 && <Text text={ring.toString()} x={CENTER - 5} y={CENTER - radius + 10} fontSize={14} fill={isBlack ? "white" : "#2c3e50"} />}</Group>); 
                   })}
                   {shots.map((s, i) => (<Circle key={i} x={s.x} y={s.y} radius={6} fill={roundColors[Math.floor(i / 10) % roundColors.length]} stroke="white" strokeWidth={2} />))}
                   {showCorrection && correctedShots.map((s, i) => (<Circle key={`c-${i}`} x={s.x} y={s.y} radius={6} fill="transparent" stroke="#27ae60" strokeWidth={3} dash={[5, 5]} />))}
                 </Layer>
              </Stage>
            </div>

            <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
              <thead>
                <tr style={{ backgroundColor: '#2c3e50', color: 'white' }}>
                  <th style={thStyle}>الجولة</th><th style={thStyle}>الطلقات</th><th style={thStyle}>المجموع</th>
                </tr>
              </thead>
              <tbody>
                {rounds.map((r, i) => (
                  <tr key={i} style={{ backgroundColor: i % 2 === 0 ? '#ecf0f1' : 'white' }}>
                    <td style={tdStyle}>{r.id}</td><td style={tdStyle}>{r.shots.map(s => s.score).join(', ')}</td><td style={{...tdStyle, fontWeight: 'bold'}}>{r.total}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      ) : (
        <div style={{ padding: '20px', backgroundColor: 'white', borderRadius: '8px', border: '1px solid #ddd' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
            <h2 style={{ margin: 0 }}>📜 أرشيف الجلسات</h2>
            <div style={{ display: 'flex', gap: '5px', backgroundColor: '#eee', padding: '5px', borderRadius: '5px' }}>
               <button onClick={() => setSortBy('date')} style={{...sortBtn, backgroundColor: sortBy === 'date' ? 'white' : 'transparent'}}>الأحدث</button>
               <button onClick={() => setSortBy('score')} style={{...sortBtn, backgroundColor: sortBy === 'score' ? 'white' : 'transparent'}}>الأعلى نتيجة</button>
            </div>
          </div>
          
          {sortedSessions.length === 0 ? <p>لا توجد جلسات محفوظة حالياً.</p> : (
            sortedSessions.map((session) => (
              <div key={session.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '15px', borderBottom: '1px solid #eee' }}>
                <div>
                  <div style={{ fontWeight: 'bold' }}>{session.date}</div>
                  <div style={{ fontSize: '14px', color: '#666' }}>المجموع: <span style={{color: '#27ae60', fontWeight: 'bold'}}>{session.total}</span> | الطلقات: {session.shots.length}</div>
                </div>
                <button onClick={() => loadSession(session)} style={{...btnStyle, backgroundColor: '#2c3e50'}}>استعادة 🔄</button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}

const btnStyle = { padding: '8px 15px', cursor: 'pointer', border: 'none', borderRadius: '4px', backgroundColor: '#3498db', color: 'white', fontWeight: 'bold' };
const tabBtn = { flex: 1, padding: '12px', cursor: 'pointer', border: 'none', color: 'white', fontWeight: 'bold', fontSize: '16px' };
const sortBtn = { padding: '5px 10px', border: 'none', borderRadius: '3px', cursor: 'pointer', fontSize: '13px', fontWeight: 'bold' };
const thStyle = { padding: '12px', border: '1px solid #bdc3c7' };
const tdStyle = { padding: '10px', border: '1px solid #bdc3c7', textAlign: 'center' };

export default App;